    tmp1 = einsum(r2, (0, 1, 2, 3), t2, (1, 4, 2, 3), (0, 4)) * -1
    r1new += einsum(tmp1, (0, 1), f.ov, (1, 2), (0, 2)) * -0.5
    r1new += einsum(tmp1, (0, 1), v.ooov, (2, 1, 0, 3), (2, 3)) * 0.5
    r1new += einsum(ints.tmp4, (0, 1), r2, (2, 0, 3, 1), (2, 3))
    r1new += einsum(ints.tmp6, (0, 1, 2, 3), r1, (0, 3), (1, 2)) * -1
    r1new += einsum(r2, (0, 1, 2, 3), ints.tmp2, (1, 3, 2, 4), (0, 4))
    tmp2 = einsum(r2, (0, 1, 2, 3), t2, (4, 5, 2, 3), (0, 1, 4, 5))
    r2new = einsum(tmp2, (0, 1, 2, 3), v.oovv, (2, 3, 4, 5), (1, 0, 5, 4)) * 0.25
    del tmp2
    r2new += einsum(ints.tmp25, (0, 1, 2, 3), r2, (0, 1, 4, 5), (2, 3, 5, 4)) * -0.5
    r2new += einsum(r2, (0, 1, 2, 3), v.vvvv, (4, 5, 3, 2), (1, 0, 5, 4)) * -0.5
    tmp3 = einsum(tmp1, (0, 1), v.oovv, (2, 1, 3, 4), (0, 2, 3, 4)) * -1
    del tmp1
    tmp6 = np.copy(np.transpose(tmp3, (0, 1, 3, 2))) * 0.5
    del tmp3
    tmp4 = np.copy(np.transpose(f.oo, (1, 0))) * 2
    tmp4 += ints.tmp9
    tmp5 = einsum(r2, (0, 1, 2, 3), tmp4, (0, 4), (1, 4, 2, 3)) * 0.5
    del tmp4
    tmp6 += np.transpose(tmp5, (1, 0, 3, 2))
    del tmp5
    r2new += tmp6
    r2new += np.transpose(tmp6, (1, 0, 2, 3)) * -1
    del tmp6
    tmp7 = einsum(v.oovv, (0, 1, 2, 3), tmp0, (4, 3), (0, 1, 4, 2)) * -1
    del tmp0
    r2new += tmp7 * -0.5
    r2new += np.transpose(tmp7, (0, 1, 3, 2)) * 0.5
    del tmp7
    tmp9 = einsum(r1, (0, 1), f.ov, (2, 3), (2, 0, 3, 1))
    tmp8 = einsum(r2, (0, 1, 2, 3), ints.tmp12, (1, 4, 3, 5), (4, 0, 5, 2))
    tmp9 += tmp8
    del tmp8
    r2new += tmp9
    r2new += np.transpose(tmp9, (0, 1, 3, 2)) * -1
    r2new += np.transpose(tmp9, (1, 0, 2, 3)) * -1
    r2new += np.transpose(tmp9, (1, 0, 3, 2))
    del tmp9
    tmp10 = einsum(r1, (0, 1), v.ooov, (2, 3, 0, 4), (2, 3, 1, 4))
    tmp12 = np.copy(np.transpose(tmp10, (1, 0, 2, 3))) * -1
    del tmp10
    tmp11 = einsum(r2, (0, 1, 2, 3), f.vv, (4, 3), (0, 1, 4, 2))
    tmp12 += np.transpose(tmp11, (1, 0, 2, 3)) * -1
    del tmp11
    r2new += tmp12 * -1
    r2new += np.transpose(tmp12, (0, 1, 3, 2))
    del tmp12
    tmp13 = einsum(r1, (0, 1), v.ovvv, (2, 1, 3, 4), (0, 2, 3, 4))
    r2new += np.transpose(tmp13, (0, 1, 3, 2))
    r2new += np.transpose(tmp13, (1, 0, 3, 2)) * -1
    del tmp13
    tmp14 = einsum(r2, (0, 1, 2, 3), ints.tmp7, (3, 4), (0, 1, 4, 2))
    r2new += np.transpose(tmp14, (1, 0, 2, 3)) * -0.5
    r2new += np.transpose(tmp14, (1, 0, 3, 2)) * 0.5
    del tmp14


    return {"r1new": r1new, "r2new": r2new}

